import{_ as a,o as s,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const l=JSON.parse('{"title":"Cosmos SDK Quickstart","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Cosmos SDK Quickstart | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"getting-started/cosmos/quickstart.md","filePath":"getting-started/cosmos/quickstart.md","lastUpdated":1772446570000}');const o=a({name:"getting-started/cosmos/quickstart.md"},[["render",function(a,l,o,t,p,c){return s(),n("div",null,[...l[0]||(l[0]=[e('<h1 id="cosmos-sdk-quickstart" tabindex="-1">Cosmos SDK Quickstart <a class="header-anchor" href="#cosmos-sdk-quickstart" aria-label="Permalink to &quot;Cosmos SDK Quickstart&quot;">​</a></h1><p>Get a Cosmos SDK chain running on Evolve using Ignite CLI.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Go 1.22+</li><li><a href="https://docs.ignite.com/welcome/install" target="_blank" rel="noreferrer">Ignite CLI</a></li></ul><h2 id="_1-start-local-da" tabindex="-1">1. Start Local DA <a class="header-anchor" href="#_1-start-local-da" aria-label="Permalink to &quot;1. Start Local DA&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">go</span><span style="color:#BFF3C2;"> install</span><span style="color:#BFF3C2;"> github.com/evstack/ev-node/tools/local-da@latest</span></span>\n<span class="line"><span style="color:#94EEFF;">local-da</span></span></code></pre></div><p>Keep this running in a separate terminal.</p><h2 id="_2-create-a-new-chain" tabindex="-1">2. Create a New Chain <a class="header-anchor" href="#_2-create-a-new-chain" aria-label="Permalink to &quot;2. Create a New Chain&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">ignite</span><span style="color:#BFF3C2;"> scaffold</span><span style="color:#BFF3C2;"> chain</span><span style="color:#BFF3C2;"> mychain</span><span style="color:#FFECB6;"> --address-prefix</span><span style="color:#BFF3C2;"> mychain</span></span>\n<span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> mychain</span></span></code></pre></div><h2 id="_3-add-evolve" tabindex="-1">3. Add Evolve <a class="header-anchor" href="#_3-add-evolve" aria-label="Permalink to &quot;3. Add Evolve&quot;">​</a></h2><p>Install the Evolve plugin for Ignite:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">ignite</span><span style="color:#BFF3C2;"> app</span><span style="color:#BFF3C2;"> install</span><span style="color:#FFECB6;"> -g</span><span style="color:#BFF3C2;"> github.com/ignite/apps/evolve</span></span></code></pre></div><p>Add Evolve to your chain:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">ignite</span><span style="color:#BFF3C2;"> evolve</span><span style="color:#BFF3C2;"> add</span></span></code></pre></div><p>This modifies your chain to use ev-abci instead of CometBFT.</p><h2 id="_4-build-and-initialize" tabindex="-1">4. Build and Initialize <a class="header-anchor" href="#_4-build-and-initialize" aria-label="Permalink to &quot;4. Build and Initialize&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">make</span><span style="color:#BFF3C2;"> install</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> init</span><span style="color:#BFF3C2;"> mynode</span><span style="color:#FFECB6;"> --chain-id</span><span style="color:#BFF3C2;"> mychain-1</span></span>\n<span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> keys</span><span style="color:#BFF3C2;"> add</span><span style="color:#BFF3C2;"> mykey</span><span style="color:#FFECB6;"> --keyring-backend</span><span style="color:#BFF3C2;"> test</span></span>\n<span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> genesis</span><span style="color:#BFF3C2;"> add-genesis-account</span><span style="color:#BFF3C2;"> mykey</span><span style="color:#BFF3C2;"> 1000000000stake</span><span style="color:#FFECB6;"> --keyring-backend</span><span style="color:#BFF3C2;"> test</span></span>\n<span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> genesis</span><span style="color:#BFF3C2;"> gentx</span><span style="color:#BFF3C2;"> mykey</span><span style="color:#BFF3C2;"> 1000000stake</span><span style="color:#FFECB6;"> --chain-id</span><span style="color:#BFF3C2;"> mychain-1</span><span style="color:#FFECB6;"> --keyring-backend</span><span style="color:#BFF3C2;"> test</span></span>\n<span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> genesis</span><span style="color:#BFF3C2;"> collect-gentxs</span></span></code></pre></div><h2 id="_5-start-the-chain" tabindex="-1">5. Start the Chain <a class="header-anchor" href="#_5-start-the-chain" aria-label="Permalink to &quot;5. Start the Chain&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.signer.passphrase</span><span style="color:#BFF3C2;"> secret</span></span></code></pre></div><p>You should see blocks being produced:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>INF block marked as DA included blockHeight=1</span></span>\n<span class="line"><span>INF block marked as DA included blockHeight=2</span></span></code></pre></div><h2 id="_6-interact" tabindex="-1">6. Interact <a class="header-anchor" href="#_6-interact" aria-label="Permalink to &quot;6. Interact&quot;">​</a></h2><p>In another terminal:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Check balance</span></span>\n<span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> query</span><span style="color:#BFF3C2;"> bank</span><span style="color:#BFF3C2;"> balances</span><span style="color:#767676;"> $(</span><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> keys</span><span style="color:#BFF3C2;"> show</span><span style="color:#BFF3C2;"> mykey</span><span style="color:#FFECB6;"> -a</span><span style="color:#FFECB6;"> --keyring-backend</span><span style="color:#BFF3C2;"> test</span><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Send tokens</span></span>\n<span class="line"><span style="color:#94EEFF;">mychaind</span><span style="color:#BFF3C2;"> tx</span><span style="color:#BFF3C2;"> bank</span><span style="color:#BFF3C2;"> send</span><span style="color:#BFF3C2;"> mykey</span><span style="color:#BFF3C2;"> mychain1...</span><span style="color:#BFF3C2;"> 1000stake</span><span style="color:#FFECB6;"> --keyring-backend</span><span style="color:#BFF3C2;"> test</span><span style="color:#FFECB6;"> --chain-id</span><span style="color:#BFF3C2;"> mychain-1</span><span style="color:#FFECB6;"> -y</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/ev-abci/integration-guide">Integrate ev-abci</a> — Manual integration without Ignite</li><li><a href="/ev-abci/migration-from-cometbft">Migrate from CometBFT</a> — Migrate an existing chain with state</li><li><a href="/guides/da-layers/celestia">Connect to Celestia</a> — Production DA layer</li></ul>',26)])])}]]);export{l as __pageData,o as default};
